== Zodiac Combinations with Kinoe (甲) == {{Wiktionary|甲|1=Kinoe (甲)|lt=Kinoe (甲)|2=ja|3=甲|4=zh|5=甲|1=Kinoe (甲)|qq=}} {| class="wikitable alternance droite" |{{ill|Yang Wood Rat|ja|甲子|1=Yang Wood Rat|1=Yang Wood Rat|zh|甲子|1=Yang Wood Rat|1=Yang Wood Rat|ko|갑자|fr|Rat de bois|de|Holz-Ratte|en|Wood Rat|lt=甲子 (Yang Wood Rat)|lt_ko=갑자|qq=|qq=draft|12=simple|13=User:Immanuelle/Yang Wood Rat|qq=}} |- style="text-align:left;font-size:100%" |{{ill|Yang Wood Dog|ja|1=Yang Wood Dog|2=ja|甲戌|zh|1=Yang Wood Dog|2=ja|甲戌|ko|갑술|fr|Chien de bois|de|Holz-Hund|en|Wood Dog|lt=甲戌 (Yang Wood Dog)|lt_ko=갑술|qq=|qq=draft|12=simple|13=User:Immanuelle/Yang Wood Dog|qq=}} |- style="text-align:left;font-size:100%" |{{ill|Yang Wood Monkey|ja|1=Yang Wood Monkey|2=ja|甲申|1=Yang Wood Monkey|zh|1=Yang Wood Monkey|2=ja|甲申|1=Yang Wood Monkey|ko|갑신|fr|Singe de bois|de|Holz-Affe|en|Wood Monkey|lt=甲申 (Yang Wood Monkey)|lt_ko=갑신|qq=|qq=draft|12=simple|13=User:Immanuelle/Yang Wood Monkey|13=User:Immanuelle/Yang Wood Monkey|qq=}} |- style="text-align:left;font-size:100%" |{{ill|Yang Wood Horse|ja|1=Yang Wood Horse|2=ja|甲午|zh|1=Yang Wood Horse|2=ja|甲午|ko|갑오|fr|Cheval de bois|de|Holz-Pferd|en|Wood Horse|lt=甲午 (Yang Wood Horse)|lt_ko=갑오|qq=|qq=draft|12=simple|13=User:Immanuelle/Yang Wood Horse|qq=}} |- style="text-align:left;font-size:100%" |{{ill|Yang Wood Dragon|ja|1=Yang Wood Dragon|2=ja|甲辰|1=Yang Wood Dragon|zh|1=Yang Wood Dragon|2=ja|甲辰|1=Yang Wood Dragon|ko|갑진|fr|Dragon de bois|de|Holz-Drache|en|Wood Dragon|lt=甲辰 (Yang Wood Dragon)|lt_ko=갑진|qq=|qq=draft|12=simple|13=User:Immanuelle/Yang Wood Dragon|qq=}} |- style="text-align:left;font-size:100%" |{{ill|Yang Wood Tiger|ja|1=Yang Wood Tiger|2=ja|甲寅|1=Yang Wood Tiger|2=ja|3=甲寅|zh|1=Yang Wood Tiger|2=ja|甲寅|1=Yang Wood Tiger|2=ja|3=甲寅|ko|갑인|fr|Tigre de bois|de|Holz-Tiger|en|Wood Tiger|lt=甲寅 (Yang Wood Tiger)|lt_ko=갑인|qq=|qq=draft|12=simple|13=User:Immanuelle/Yang Wood Tiger|13=User:Immanuelle/Yang Wood Tiger|qq=}} |}
